                    CREATE View [SSRS].[Leagues_Division_EndofSeason]  as    SELECT [League_ID]        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name        ,[Division_Of_Fixture]        ,[No Result]        ,[Year_Of_Fixture]        ,SUM([Abandoned]   )[Abandoned]        ,SUM([Cancelled]   )[Cancelled]        ,SUM([Conceded]   )[Conceded]        ,SUM([InProgress]   )[InProgress]        ,SUM([Win]    )[Win]        ,SUM([ShortSided]   )[ShortSided]    FROM [SSRS].[Leagues_Division_STD_2026]    Group by [League_ID]        ,[Name]        ,[Division_Of_Fixture]        ,[No Result]        ,[Year_Of_Fixture]    